INSERT INTO ui_translations (key, lang, value, updated_at) VALUES
  ('doc_tab_start', 'en', 'Start', CURRENT_TIMESTAMP),
  ('doc_tab_study', 'en', 'Study', CURRENT_TIMESTAMP),
  ('doc_tab_create', 'en', 'Create', CURRENT_TIMESTAMP),
  ('doc_start_intro_title', 'en', 'Getting Started', CURRENT_TIMESTAMP),
  ('doc_start_intro_desc', 'en', 'Use this tab when you are learning how the dashboard, library, progress, and social features fit together.', CURRENT_TIMESTAMP),
  ('doc_study_intro_title', 'en', 'Study', CURRENT_TIMESTAMP),
  ('doc_study_intro_desc', 'en', 'This tab explains how to move through content, choose the right mode, and tune your sessions for review or recall.', CURRENT_TIMESTAMP),
  ('doc_create_intro_title', 'en', 'Create', CURRENT_TIMESTAMP),
  ('doc_create_intro_desc', 'en', 'This tab covers how creators organize content, localize it, and publish useful study material without overcomplicating the workflow.', CURRENT_TIMESTAMP),
  ('doc_start_quick_title', 'en', 'Quick Start', CURRENT_TIMESTAMP),
  ('doc_start_quick_desc', 'en', 'Pick a pillar on the dashboard, open a subject, and start with Learn. Use favorites and filters to narrow the library, then review your XP, streaks, and daily goal from your profile.', CURRENT_TIMESTAMP),
  ('doc_start_dashboard_title', 'en', 'Dashboard, Search, and Filters', CURRENT_TIMESTAMP),
  ('doc_start_dashboard_desc', 'en', 'The dashboard is your main library. Use search to find content quickly, then combine source filters such as favorites, mine, and public library with age filters to reduce noise.', CURRENT_TIMESTAMP),
  ('doc_start_structure_title', 'en', 'Subjects, Folders, and Collections', CURRENT_TIMESTAMP),
  ('doc_start_structure_desc', 'en', 'Subjects hold cards. Folders group related content inside a pillar. Collections are curated sets that can combine multiple subjects for study and sharing.', CURRENT_TIMESTAMP),
  ('doc_start_progress_title', 'en', 'Progress and Goals', CURRENT_TIMESTAMP),
  ('doc_start_progress_desc', 'en', 'Your profile shows total XP, current streak, max streak, and daily goal progress. Session size and number of answers are also managed from the profile page.', CURRENT_TIMESTAMP),
  ('doc_start_feedback_title', 'en', 'Feedback and Help', CURRENT_TIMESTAMP),
  ('doc_start_feedback_desc', 'en', 'Use the feedback entry points across the app when something is wrong or unclear. Reports can include the current context, which makes content issues easier to review and fix.', CURRENT_TIMESTAMP),
  ('doc_study_how_title', 'en', 'How to Study', CURRENT_TIMESTAMP),
  ('doc_study_how_desc', 'en', 'Start with Learn when you are building recognition, then switch to Test when you want faster recall and stricter checking. Use shorter sessions for focused review and larger sessions for broader coverage.', CURRENT_TIMESTAMP),
  ('doc_study_modes_title', 'en', 'Learn and Test Modes', CURRENT_TIMESTAMP),
  ('doc_study_modes_desc', 'en', 'Learn and Test are the core study modes. They use the same content but support different pacing and answer expectations, so switch modes based on whether you are exploring or checking retention.', CURRENT_TIMESTAMP),
  ('doc_study_scope_title', 'en', 'Subjects, Folders, and Collections in Study', CURRENT_TIMESTAMP),
  ('doc_study_scope_desc', 'en', 'Study can start from a single subject, a folder view, or a collection. Collections are useful when you want a mixed session across several subjects without leaving the current flow.', CURRENT_TIMESTAMP),
  ('doc_study_media_title', 'en', 'Audio, Autoplay, and Media', CURRENT_TIMESTAMP),
  ('doc_study_media_desc', 'en', 'When media is available, use it to reinforce pronunciation and recognition. Autoplay is most useful for passive review or repeated listening during shorter sessions.', CURRENT_TIMESTAMP),
  ('doc_create_model_title', 'en', 'Content Model', CURRENT_TIMESTAMP),
  ('doc_create_model_desc', 'en', 'Creators work inside pillars and organize material with folders, subjects, collections, and cards. Build the structure first, then fill it with localized prompts, answers, and optional media.', CURRENT_TIMESTAMP),
  ('doc_create_visibility_title', 'en', 'Ownership and Visibility', CURRENT_TIMESTAMP),
  ('doc_create_visibility_desc', 'en', 'Use "mine" to work on your own content, favorites to pin useful items, and public library to browse shared material. Public visibility affects discovery, while ownership affects what you can edit or delete.', CURRENT_TIMESTAMP),
  ('doc_create_localization_title', 'en', 'Localization', CURRENT_TIMESTAMP),
  ('doc_create_localization_desc', 'en', 'Localize content where it matters most: names, descriptions, prompts, and answers. Keep labels consistent across languages so users can switch study language without losing structure.', CURRENT_TIMESTAMP),
  ('doc_create_media_title', 'en', 'Media Workflow', CURRENT_TIMESTAMP),
  ('doc_create_media_desc', 'en', 'Images, audio, and video should support the learning goal, not distract from it. Add media when it improves recognition, pronunciation, or context, and keep cards usable even when media is missing.', CURRENT_TIMESTAMP),
  ('doc_create_json_title', 'en', 'Advanced JSON Import', CURRENT_TIMESTAMP),
  ('doc_create_json_desc', 'en', 'JSON-based creation is an advanced workflow for structured bulk content. It should remain optional; most creators should be able to build and edit content through the standard forms.', CURRENT_TIMESTAMP)
